// sleepCtx sleeps for d unless ctx is cancelled first.
func sleepCtx(ctx context.Context, d time.Duration) error {
	if d <= 0 {
		return nil
	}
	t := time.NewTimer(d)
	defer t.Stop()
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-t.C:
		return nil
	}
}

// putter is the minimal client surface bulk needs. Mirrors *client.Client's
// Put, but as an interface so tests can inject a fake (e.g. a 429-returner).
type putter interface {
	Put(ctx context.Context, path string, body any) (json.RawMessage, int, error)
}

// bulkSummary is the machine-readable outcome of a bulk run.
type bulkSummary struct {
	Verb          string   `json:"verb"`
	Total         int      `json:"total"`
	Applied       int      `json:"applied"`
	Failed        int      `json:"failed"`
	DryRun        bool     `json:"dry_run"`
	FetchFailures []string `json:"fetch_failures"`
	Errors        []string `json:"errors,omitempty"`
}

func newNovelBulkCmd(flags *rootFlags) *cobra.Command {
	var flagQuery string
	var flagSet []string
	var flagIDs string
	var flagConcurrency int
	var flagApply bool

	cmd := &cobra.Command{
		Use:     "bulk [move|reassign]",
		Short:   "Applies field updates (stage, owner, custom fields) to many opportunities at once",
		Example: "move --query stale.json --set pipeline_stage_id=9 --concurrency 4 --apply",
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}

			verb := "move"
			if len(args) > 0 {
				verb = args[0]
			}
			if verb != "move" && verb != "reassign" {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("verb must be move or reassign (got %q)", verb))
			}

			set, err := parseSetFields(flagSet)
			if err != nil {
				_ = cmd.Usage()
				return usageErr(err)
			}
			if dryRunOK(flags) {
				fmt.Fprintf(cmd.OutOrStdout(), "would %s with fields %v\n", verb, set)
				return nil
			}
			if len(set) == 0 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("at least one --set key=value is required"))
			}

			ids, err := resolveBulkIDs(flagQuery, flagIDs)
			if err != nil {
				return usageErr(err)
			}
			if len(ids) == 0 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("no ids resolved: provide --ids or --query"))
			}

			concurrency := flagConcurrency
			if concurrency <= 0 {
				concurrency = 3
			}

			// Preview by default. Mutate only with --apply, and never under the
			// verifier (which sets PRINTING_PRESS_VERIFY=1) — both paths print a
			// plan and exit 0.
			if !flagApply || cliutil.IsVerifyEnv() {
				summary := bulkSummary{Verb: verb, Total: len(ids), DryRun: true}
				return renderBulkSummary(cmd.OutOrStdout(), summary, ids, set, flags)
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}
			summary := runBulk(cmd.Context(), c, verb, ids, set, concurrency)
			if rerr := renderBulkSummary(cmd.OutOrStdout(), summary, ids, set, flags); rerr != nil {
				return rerr
			}
			if summary.Failed > 0 {
				return apiErr(fmt.Errorf("bulk %s: %d of %d updates failed", verb, summary.Failed, summary.Total))
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&flagQuery, "query", "", "JSON file of opportunity objects or ids to update")
	cmd.Flags().StringArrayVar(&flagSet, "set", nil, "Field to set as key=value (repeatable)")
	cmd.Flags().StringVar(&flagIDs, "ids", "", "Comma-separated opportunity ids (alternative to --query)")
	cmd.Flags().IntVar(&flagConcurrency, "concurrency", 3, "Number of concurrent updates")
	cmd.Flags().BoolVar(&flagApply, "apply", false, "Perform the updates (default: preview only)")
	return cmd
}

// parseSetFields turns ["pipeline_stage_id=9","assignee_id=7"] into a typed
// map. Numeric-looking values are coerced to numbers so the API receives the
// right JSON shape.
func parseSetFields(pairs []string) (map[string]any, error) {
	out := map[string]any{}
	for _, p := range pairs {
		kv := strings.SplitN(p, "=", 2)
		if len(kv) != 2 || strings.TrimSpace(kv[0]) == "" {
			return nil, fmt.Errorf("invalid --set %q (want key=value)", p)
		}
		key := strings.TrimSpace(kv[0])
		val := strings.TrimSpace(kv[1])
		if n, err := strconv.ParseInt(val, 10, 64); err == nil {
			out[key] = n
		} else if f, err := strconv.ParseFloat(val, 64); err == nil {
			out[key] = f
		} else {
			out[key] = val
		}
	}
	return out, nil
}

// resolveBulkIDs collects opportunity ids from a --ids csv and/or a --query
// JSON file (array of ids, or array of objects each with an "id").
func resolveBulkIDs(queryFile, idsCSV string) ([]string, error) {
	seen := map[string]bool{}
	var ids []string
	var bad []string
	add := func(s string) {
		s = strings.TrimSpace(s)
		if s == "" || seen[s] {
			return
		}
		// Opportunity ids are numeric. Reject anything else so a crafted id
		// (path traversal, query/fragment) cannot redirect the PUT to a
		// different endpoint or resource — the client does no path cleaning.
		if !isNumericID(s) {
			bad = append(bad, s)
			return
		}
		seen[s] = true
		ids = append(ids, s)
	}

	for _, raw := range strings.Split(idsCSV, ",") {
		add(raw)
	}

	if queryFile != "" {
		data, err := os.ReadFile(queryFile)
		if err != nil {
			return nil, fmt.Errorf("reading --query file: %w", err)
		}
		// Try array of objects first, then array of scalars.
		var objs []map[string]any
		if err := json.Unmarshal(data, &objs); err == nil {
			for _, o := range objs {
				if v, ok := o["id"]; ok {
					add(fmt.Sprintf("%v", normalizeID(v)))
				}
			}
		} else {
			var scalars []any
			if err := json.Unmarshal(data, &scalars); err != nil {
				return nil, fmt.Errorf("parsing --query JSON (want array of ids or objects): %w", err)
			}
			for _, v := range scalars {
				add(fmt.Sprintf("%v", normalizeID(v)))
			}
		}
	}
	if len(bad) > 0 {
		return nil, usageErr(fmt.Errorf("invalid opportunity id(s) (must be numeric): %s", strings.Join(bad, ", ")))
	}
	return ids, nil
}

// isNumericID reports whether s is a plain integer id, the only shape a Copper
// resource id takes. Used to keep user-supplied ids from manipulating request
// paths.
func isNumericID(s string) bool {
	s = strings.TrimSpace(s)
	if s == "" {
		return false
	}
	_, err := strconv.ParseInt(s, 10, 64)
	return err == nil
}

// normalizeID renders a JSON-decoded id (often float64) without a trailing
// ".0" so "88" not "88".
func normalizeID(v any) any {
	if f, ok := v.(float64); ok && f == float64(int64(f)) {
		return int64(f)
	}
	return v
}

// runBulk applies the field set to each id via a bounded worker pool. A 429
// surfaced by the client is recorded as a RateLimitError-flavored failure
// (never silently dropped). The returned summary always reflects every id.
func runBulk(ctx context.Context, c putter, verb string, ids []string, set map[string]any, concurrency int) bulkSummary {
	summary := bulkSummary{Verb: verb, Total: len(ids)}
	if concurrency <= 0 {
		concurrency = 1
	}

	var mu sync.Mutex
	sem := make(chan struct{}, concurrency)
	var wg sync.WaitGroup

	for _, id := range ids {
		id := id
		wg.Add(1)
		sem <- struct{}{}
		go func() {
			defer wg.Done()
			defer func() { <-sem }()
			err := putWithRetry(ctx, c, "/opportunities/"+id, set, 5)
			mu.Lock()
			defer mu.Unlock()
			if err != nil {
				summary.Failed++
				summary.Errors = append(summary.Errors, fmt.Sprintf("%s: %v", id, err))
			} else {
				summary.Applied++
			}
		}()
	}
	wg.Wait()
	sort.Strings(summary.Errors)
	return summary
}

// putWithRetry issues a PUT with exponential backoff on HTTP 429. After the
// retry budget is exhausted it returns a *cliutil.RateLimitError so a throttle
// can never masquerade as success or as empty data.
func putWithRetry(ctx context.Context, c putter, path string, body any, maxRetries int) error {
	var lastStatus int
	for attempt := 0; attempt <= maxRetries; attempt++ {
		_, status, err := c.Put(ctx, path, body)
		lastStatus = status
		if status == 429 {
			if attempt == maxRetries {
				return &cliutil.RateLimitError{URL: path}
			}
			if werr := sleepCtx(ctx, cliutil.Backoff(attempt)); werr != nil {
				return werr
			}
			continue
		}
		if err != nil {
			return err
		}
		if status >= 200 && status < 300 {
			return nil
		}
		return fmt.Errorf("PUT %s: unexpected status %d", path, status)
	}
	return fmt.Errorf("PUT %s: exhausted retries (last status %d)", path, lastStatus)
}

func renderBulkSummary(w io.Writer, summary bulkSummary, ids []string, set map[string]any, flags *rootFlags) error {
	if summary.FetchFailures == nil {
		summary.FetchFailures = []string{}
	}
	if flags.asJSON || flags.agent {
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(summary)
	}
	if summary.DryRun {
		fmt.Fprintf(w, "PREVIEW: would %s %d opportunit(ies) with %v\n", summary.Verb, summary.Total, set)
		for _, id := range ids {
			fmt.Fprintf(w, "  - PUT /opportunities/%s %v\n", id, set)
		}
		fmt.Fprintln(w, "(re-run with --apply to execute)")
		return nil
	}
	fmt.Fprintf(w, "%s: %d applied, %d failed (of %d)\n", summary.Verb, summary.Applied, summary.Failed, summary.Total)
	for _, e := range summary.Errors {
		fmt.Fprintf(w, "  FAIL %s\n", e)
	}
	return nil
}
